// 搜索函数
function searchSite(query) {
    if (!query || query.length < 2) return [];
    query = query.toLowerCase().trim();
    var words = query.split(/\s+/);
    var results = [];
    
    for (var i = 0; i < SEARCH_INDEX.length; i++) {
        var page = SEARCH_INDEX[i];
        var score = 0;
        var matched = true;
        
        for (var w = 0; w < words.length; w++) {
            var word = words[w];
            if (page.s.indexOf(word) === -1) {
                matched = false;
                break;
            }
            // 标题匹配加分
            if (page.t.toLowerCase().indexOf(word) !== -1) score += 10;
            // 关键词匹配加分
            if (page.k.toLowerCase().indexOf(word) !== -1) score += 5;
            // 描述匹配
            if (page.d.toLowerCase().indexOf(word) !== -1) score += 2;
            // 可搜索文本匹配
            score += 1;
        }
        
        if (matched && score > 0) {
            results.push({
                path: page.p,
                title: page.t,
                desc: page.d,
                score: score
            });
        }
    }
    
    // 按分数排序
    results.sort(function(a, b) { return b.score - a.score; });
    
    // 返回前20条
    return results.slice(0, 20);
}

// 显示搜索结果
function showSearchResults(query) {
    var results = searchSite(query);
    var container = document.getElementById('searchResults');
    if (!container) {
        container = document.createElement('div');
        container.id = 'searchResults';
        container.style.cssText = 'position:absolute;top:100%;left:0;right:0;background:#fff;border:1px solid #ddd;border-radius:0 0 6px 6px;max-height:400px;overflow-y:auto;z-index:1000;box-shadow:0 4px 12px rgba(0,0,0,.15);display:none;';
        var searchBox = document.querySelector('.search-box');
        if (searchBox) {
            searchBox.style.position = 'relative';
            searchBox.appendChild(container);
        }
    }
    
    if (results.length === 0) {
        container.innerHTML = '<div style="padding:15px;color:#666;text-align:center">未找到相关结果</div>';
        container.style.display = 'block';
        return;
    }
    
    var html = '';
    for (var i = 0; i < results.length; i++) {
        var r = results[i];
        html += '<a href="' + r.path + '" style="display:block;padding:10px 15px;border-bottom:1px solid #f0f0f0;text-decoration:none;color:#333;transition:background .2s" onmouseover="this.style.background=#f5f5f5" onmouseout="this.style.background=#fff">';
        html += '<div style="font-weight:600;font-size:14px;color:#2c3e50">' + r.title + '</div>';
        if (r.desc) {
            html += '<div style="font-size:12px;color:#666;margin-top:3px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + r.desc + '</div>';
        }
        html += '<div style="font-size:11px;color:#999;margin-top:2px">' + r.path + '</div>';
        html += '</a>';
    }
    
    container.innerHTML = html;
    container.style.display = 'block';
}

// 隐藏搜索结果
function hideSearchResults() {
    var container = document.getElementById('searchResults');
    if (container) container.style.display = 'none';
}

// 绑定搜索事件
document.addEventListener('DOMContentLoaded', function() {
    var searchInput = document.getElementById('searchInput');
    if (searchInput) {
        searchInput.addEventListener('input', function() {
            var query = this.value.trim();
            if (query.length >= 2) {
                showSearchResults(query);
            } else {
                hideSearchResults();
            }
        });
        
        searchInput.addEventListener('focus', function() {
            var query = this.value.trim();
            if (query.length >= 2) {
                showSearchResults(query);
            }
        });
        
        // 点击外部隐藏
        document.addEventListener('click', function(e) {
            if (!e.target.closest('.search-box')) {
                hideSearchResults();
            }
        });
        
        // 回车跳转到第一个结果
        searchInput.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') {
                var query = this.value.trim();
                if (query.length >= 2) {
                    var results = searchSite(query);
                    if (results.length > 0) {
                        window.location.href = results[0].path;
                    }
                }
            }
        });
    }
});
